const now = new Date();
const weekStart = new Date(now);
weekStart.setDate(now.getDate() - 7);

const prompt = `Tu es un analyste tech senior. Génère un digest hebdomadaire de veille technologique pour la semaine du ${weekStart.toLocaleDateString('fr-FR')} au ${now.toLocaleDateString('fr-FR')}.

Structure ton rapport en 3 sections :
1. **Tendances clés** (3-5 tendances majeures de la semaine en IA, Data, Cloud, DevOps, Sécurité)
2. **Top articles** (5 articles les plus impactants avec titre + résumé 1 phrase)
3. **Statistiques** (résumé des domaines les plus actifs)

Sois concis et factuel. Réponds en français.`;

return [{ json: { prompt } }];

const text = $input.first().json.text;
const now = new Date();
const weekStart = new Date(now);
weekStart.setDate(now.getDate() - 7);

const description = text.length > 4000 ? text.substring(0, 4000) + '...' : text;

return [{
  json: {
    content: '',
    embeds: [{
      title: `📊 Digest Hebdomadaire — ${weekStart.toLocaleDateString('fr-FR')} au ${now.toLocaleDateString('fr-FR')}`,
      description: description,
      color: 5793266,
      footer: { text: 'Veille Pro - Digest Hebdo' },
      timestamp: new Date().toISOString()
    }]
  }
}];
